const pageItems = $('Get recipes').all();
const blockItems = $input.all();

// ---------- page meta map ----------
const pageMetaById = {};

for (const item of pageItems) {
  const page = item.json;
  const pageId = page.id;
  if (!pageId) continue;

  const tags = [
    ...(page.property_tags || []),
    page.property_meal_type || "",
  ].filter(Boolean);

  pageMetaById[pageId] = {
    title: page.property_name || page.name || "Ohne Titel",
    rating: page.property_rating_calc || "",
    tags: [...new Set(tags)],
    description: page.property_description || "",
  };
}

// ---------- group blocks by page_id ----------
const blocksByPageId = {};

for (const item of blockItems) {
  const block = item.json;
  const pageId = block.parent?.page_id;

  if (!pageId) continue;

  const type = block.type;
  const raw = (block.content || "").trim();

  if (!raw) continue;

  let text;

  if (type === "heading_1") {
    text = `# ${raw}`;
  } else if (type === "heading_2") {
    text = `## ${raw}`;
  } else if (type === "heading_3") {
    text = `### ${raw}`;
  } else if (type === "bulleted_list_item") {
    text = `- ${raw}`;
  } else if (type === "numbered_list_item") {
    text = `1. ${raw}`;
  } else if (type === "to_do") {
    text = `[ ] ${raw}`;
  } else if (["paragraph", "quote", "callout", "toggle"].includes(type)) {
    text = raw;
  } else {
    continue;
  }

  if (!blocksByPageId[pageId]) {
    blocksByPageId[pageId] = [];
  }

  blocksByPageId[pageId].push(text);
}

// ---------- build final document ----------
const sections = [];

for (const pageId of Object.keys(pageMetaById)) {
  const meta = pageMetaById[pageId];
  const contentLines = blocksByPageId[pageId] || [];
  const content = contentLines.join("\n");

  const section = [
    `<!-- RECIPE_START: ${pageId} -->`,
    ``,
    `Title: ${meta.title}`,
    `Rating: ${meta.rating}`,
    `Tags: ${meta.tags.join(", ")}`,
    meta.description ? `Description: ${meta.description}` : "",
    ``,
    `Content:`,
    content,
    ``,
    `<!-- RECIPE_END: ${pageId} -->`,
  ]
    .filter(line => line !== "")
    .join("\n");

  sections.push(section);
}

// ---------- full doc ----------
const finalDoc = [
  `# Rezepte`,
  ``,
  sections.join("\n\n"),
].join("\n");

return [
  {
    json: {
      content: finalDoc,
    },
  },
];
